package net.minecraft.entity; import net.minecraft.item.ItemStack; import net.minecraft.scoreboard.Team; public class EntityLivingBase extends Entity { public int hurtTime; private Team team; public float getHealth(){return 20f;} public ItemStack getHeldItem(){return null;} public Team getTeam(){return team;} public void setTeamForTest(Team value){team=value;} public boolean isOnSameTeam(EntityLivingBase other){return team!=null&&team.isSameTeam(other.getTeam());} }
